content.text:
`do-while` dövrünün sintaksisi belədir:
do {
  // icra olunacaq kod
} while (condition);
- **Kod bloku**: Ən azı bir dəfə icra olunur.
- **Şərt (condition)**: Kod bloku icra olunduqdan sonra yoxlanılır. Şərt doğru olarsa, dövrə təkrarlanır.
Dəyişən adətən dövrədən əvvəl təyin edilir və yeniləmə kod bloku daxilində aparılır.

content.code:
#include <iostream>

int main() {
  int counter = 1;
  do {
    std::cout << "Number: " << counter << std::endl;
    counter++;
  } while (counter <= 5);
  return 0;
}
// Output:
// Number: 1
// Number: 2
// Number: 3
// Number: 4
// Number: 5

#include <iostream>

int main() {
  int i = 1;
  do {
    int j = 1;
    do {
      std::cout << "(" << i << "," << j << ") ";
      j++;
    } while (j <= 3);
    std::cout << std::endl;
    i++;
  } while (i <= 3);
  return 0;
}
// Output:
// (1,1) (1,2) (1,3)
// (2,1) (2,2) (2,3)
// (3,1) (3,2) (3,3)

#include <iostream>

int main() {
  int sum = 0;
  int i = 1;
  do {
    sum += i;
    i++;
  } while (i <= 4);
  std::cout << "Sum: " << sum << std::endl;
  return 0;
}
// Output:
// Sum: 10

